func  (this *XtCore) ParseMarkets(markets any) any  {
    var result any = []any{}
    for i := 0; IsLessThan(i, GetArrayLength(markets)); i++ {
        AppendToArray(&result, this.ParseMarket(GetValue(markets, i)))
    }
    return result
}
