    //        "p": "30000",                   // trade price
    //        "q": "3",                       // qty quantity
    //        "v": "90000"                    // volume trade amount
    //    }
    //
    // swap and future: fetchTrades
    //
    //     {
    //         "t": 1678227683897,
    //         "s": "btc_usdt",
    //         "p": "22031",
    //         "a": "1067",
    //         "m": "BID"
    //     }
    //
    // spot: fetchMyTrades
    //
    //     {
    //         "symbol": "btc_usdt",
    //         "tradeId": "206906233569974658",
    //         "orderId": "206906233178463488",
